import React from "react";
import { Link, useNavigate } from "react-router-dom";

const Navbar = () => {
  const navigate = useNavigate();

  // Read user from localStorage
  let user = null;
  try {
    user = JSON.parse(localStorage.getItem("user"));
  } catch {
    user = null;
  }

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <nav className="bg-blue-600 text-white px-6 py-4 flex justify-between items-center">
      <div className="font-bold text-xl cursor-pointer" onClick={() => navigate("/")}>
        EventHub
      </div>
      <div className="space-x-4">
        {user ? (
          <>
            {user.role === "participant" && (
              <>
                <Link to="/participant/dashboard" className="hover:underline">
                  Dashboard
                </Link>
                <Link to="/browse-events" className="hover:underline">
                  Browse Events
                </Link>
                <Link to="/clubs" className="hover:underline">
                  Clubs
                </Link>
              </>
            )}
            {user.role === "organizer" && (
              <>
                <Link to="/organizer/dashboard" className="hover:underline">
                  Dashboard
                </Link>
                <Link to="/create-event" className="hover:underline">
                  Create Event
                </Link>
              </>
            )}
            <Link to="/profile" className="hover:underline">
              Profile
            </Link>
            <button
              onClick={handleLogout}
              className="bg-red-500 hover:bg-red-600 px-3 py-1 rounded"
            >
              Logout
            </button>
          </>
        ) : (
          <Link to="/login" className="hover:underline">
            Login
          </Link>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
